components.css:
.ds-btn {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  gap: 8px;
  height: 36px;
  padding: 0 16px;
  font-family: 'Chillax-Variable', 'Chillax', system-ui, sans-serif;
  font-size: 0.8125rem;
  font-weight: 500;
  line-height: 1;
  color: #161a22;
  background: linear-gradient(180deg, hsl(210 20% 99%) 0%, hsl(212 16% 94%) 48%, hsl(214 14% 89%) 100%);
  border: 1px solid #8996a9;
  border-radius: 5px;
  box-shadow: inset 0 1px 0 hsl(0 0% 100% / 0.7), inset 0 -1px 0 hsl(220 20% 30% / 0.12);
  cursor: pointer;
  white-space: nowrap;
  user-select: none;
  transition: filter 90ms cubic-bezier(0.4, 0, 0.2, 1), transform 120ms cubic-bezier(0.34, 1.56, 0.64, 1), box-shadow 90ms cubic-bezier(0.4, 0, 0.2, 1);
}
.ds-btn:hover {
  filter: brightness(1.03);
  border-color: #161a22;
}
.ds-btn:active {
  background: linear-gradient(180deg, hsl(214 14% 88%) 0%, hsl(212 16% 92%) 100%);
  transform: translateY(1px);
  box-shadow: inset 0 1px 2px hsl(220 20% 20% / 0.16), inset 0 -1px 0 hsl(0 0% 100% / 0.5);
}
.ds-btn:focus-visible {
  outline: 2px solid #ff570f;
  outline-offset: 1px;
}

.ds-btn-primary {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  gap: 8px;
  height: 36px;
  padding: 0 16px;
  font-family: 'Chillax-Variable', 'Chillax', system-ui, sans-serif;
  font-size: 0.8125rem;
  font-weight: 500;
  line-height: 1;
  color: #f9fafb;
  background: #161a22;
  border: 1px solid #161a22;
  border-radius: 5px;
  box-shadow: inset 0 1px 0 hsl(0 0% 100% / 0.14);
  cursor: pointer;
  white-space: nowrap;
  user-select: none;
  transition: filter 90ms cubic-bezier(0.4, 0, 0.2, 1), box-shadow 90ms cubic-bezier(0.4, 0, 0.2, 1);
}
.ds-btn-primary:hover {
  filter: brightness(1.18);
}
.ds-btn-primary:active {
  filter: brightness(1);
  box-shadow: inset 0 2px 4px hsl(0 0% 0% / 0.4);
}
.ds-btn-primary:focus-visible {
  outline: 2px solid #ff570f;
  outline-offset: 1px;
}

.ds-btn-accent {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  gap: 8px;
  height: 36px;
  padding: 0 16px;
  font-family: 'Chillax-Variable', 'Chillax', system-ui, sans-serif;
  font-size: 0.8125rem;
  font-weight: 600;
  line-height: 1;
  color: #29140a;
  background: #ff570f;
  border: 1px solid #e6410a;
  border-radius: 5px;
  box-shadow: inset 0 1px 0 hsl(0 0% 100% / 0.3);
  cursor: pointer;
  white-space: nowrap;
  user-select: none;
  transition: background 160ms cubic-bezier(0.4, 0, 0.2, 1), box-shadow 120ms cubic-bezier(0.34, 1.56, 0.64, 1);
}
.ds-btn-accent:hover {
  background: #ff6929;
}
.ds-btn-accent:active {
  background: #e6410a;
  box-shadow: inset 0 2px 4px hsl(20 60% 10% / 0.4);
}
.ds-btn-accent:focus-visible {
  outline: 2px solid #ff570f;
  outline-offset: 1px;
}

.ds-btn-ghost {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  gap: 8px;
  height: 36px;
  padding: 0 16px;
  font-family: 'Chillax-Variable', 'Chillax', system-ui, sans-serif;
  font-size: 0.8125rem;
  font-weight: 500;
  line-height: 1;
  color: #444a55;
  background: transparent;
  border: 1px solid transparent;
  border-radius: 5px;
  box-shadow: none;
  cursor: pointer;
  white-space: nowrap;
  user-select: none;
  transition: background 90ms cubic-bezier(0.4, 0, 0.2, 1), color 90ms cubic-bezier(0.4, 0, 0.2, 1);
}
.ds-btn-ghost:hover {
  background: #e1e5ea;
  color: #161a22;
}
.ds-btn-ghost:active {
  background: #d6dbe1;
  transform: translateY(1px);
}
.ds-btn-ghost:focus-visible {
  outline: 2px solid #ff570f;
  outline-offset: 1px;
}

.ds-input {
  width: 100%;
  height: 36px;
  padding: 0 12px;
  font-family: 'Chillax-Variable', 'Chillax', system-ui, sans-serif;
  font-size: 0.8125rem;
  color: #161a22;
  background: #e2e5e9;
  border: 1px solid #8996a9;
  border-radius: 5px;
  box-shadow: inset 0 1px 2px hsl(220 20% 20% / 0.16), inset 0 -1px 0 hsl(0 0% 100% / 0.5);
  transition: border-color 90ms cubic-bezier(0.4, 0, 0.2, 1), box-shadow 90ms cubic-bezier(0.4, 0, 0.2, 1);
}
.ds-input::placeholder {
  color: #9097a2;
}
.ds-input:hover {
  border-color: #161a22;
}
.ds-input:focus {
  outline: none;
  border-color: #ff570f;
  box-shadow: inset 0 1px 2px hsl(220 20% 20% / 0.16), inset 0 -1px 0 hsl(0 0% 100% / 0.5), 0 0 0 2px hsl(18 100% 53% / 0.12);
}

.ds-toggle {
  display: inline-flex;
  align-items: center;
  gap: 8px;
  font-size: 0.8125rem;
  cursor: pointer;
  user-select: none;
}
.ds-toggle input {
  appearance: none;
  width: 40px;
  height: 22px;
  background: #e2e5e9;
  border: 1px solid #8996a9;
  border-radius: 9999px;
  box-shadow: inset 0 1px 2px hsl(220 20% 20% / 0.16), inset 0 -1px 0 hsl(0 0% 100% / 0.5);
  position: relative;
  flex-shrink: 0;
  cursor: pointer;
  transition: background 90ms cubic-bezier(0.4, 0, 0.2, 1), border-color 90ms cubic-bezier(0.4, 0, 0.2, 1);
}
.ds-toggle input::after {
  content: '';
  position: absolute;
  top: 1px;
  left: 1px;
  width: 18px;
  height: 18px;
  background: linear-gradient(180deg, hsl(210 20% 99%) 0%, hsl(212 16% 94%) 48%, hsl(214 14% 89%) 100%);
  border: 1px solid #8996a9;
  border-radius: 9999px;
  box-shadow: inset 0 1px 0 hsl(0 0% 100% / 0.7), inset 0 -1px 0 hsl(220 20% 30% / 0.12);
  transition: transform 120ms cubic-bezier(0.34, 1.56, 0.64, 1);
}
.ds-toggle input:checked {
  background: #ff570f;
  border-color: #e6410a;
}
.ds-toggle input:checked::after {
  transform: translateX(18px);
}
.ds-toggle input:focus-visible {
  outline: 2px solid #ff570f;
  outline-offset: 1px;
}

.ds-badge {
  display: inline-flex;
  align-items: center;
  gap: 4px;
  height: 20px;
  padding: 0 8px;
  font-family: ui-monospace, 'Cascadia Mono', 'Cascadia Code', Consolas, 'SFMono-Regular', Menlo, 'JetBrains Mono', monospace;
  font-size: 0.6875rem;
  font-weight: 500;
  letter-spacing: 0.04em;
  text-transform: uppercase;
  line-height: 1;
  color: #444a55;
  background: #eaedf0;
  border: 1px solid #b1b9c4;
  border-radius: 3px;
  white-space: nowrap;
  user-select: none;
}

.ds-badge-accent {
  display: inline-flex;
  align-items: center;
  gap: 4px;
  height: 20px;
  padding: 0 8px;
  font-family: ui-monospace, 'Cascadia Mono', 'Cascadia Code', Consolas, 'SFMono-Regular', Menlo, 'JetBrains Mono', monospace;
  font-size: 0.6875rem;
  font-weight: 500;
  letter-spacing: 0.04em;
  text-transform: uppercase;
  line-height: 1;
  color: #29140a;
  background: #ff570f;
  border: 1px solid #e6410a;
  border-radius: 3px;
  white-space: nowrap;
  user-select: none;
}

.ds-panel {
  background: #f9fafb;
  border: 1px solid #b1b9c4;
  border-radius: 5px;
  padding: 16px;
  box-shadow: inset 0 1px 0 hsl(0 0% 100% / 0.7), inset 0 -1px 0 hsl(220 20% 30% / 0.12);
}
.ds-panel-title {
  font-family: 'ClashDisplay-Variable', 'ClashDisplay', 'Archivo', system-ui, sans-serif;
  font-size: 1.375rem;
  font-weight: 600;
  line-height: 1.08;
  letter-spacing: -0.015em;
  color: #161a22;
  margin: 0 0 8px 0;
}
.ds-panel-body {
  font-family: 'Chillax-Variable', 'Chillax', system-ui, sans-serif;
  font-size: 0.875rem;
  line-height: 1.5;
  color: #161a22;
  margin: 0;
}

.ds-nav {
  position: sticky;
  top: 0;
  z-index: 50;
  background: #d3d8de;
  border-bottom: 1px solid #b1b9c4;
}
.ds-nav-inner {
  display: flex;
  align-items: center;
  justify-content: space-between;
  max-width: 72rem;
  margin: 0 auto;
  padding: 0 16px;
  height: 56px;
}
.ds-nav-brand {
  font-family: 'ClashDisplay-Variable', 'ClashDisplay', system-ui, sans-serif;
  font-size: 1.375rem;
  font-weight: 700;
  color: #161a22;
  text-decoration: none;
  letter-spacing: -0.015em;
}
.ds-nav-links {
  display: flex;
  align-items: center;
  gap: 24px;
}
.ds-nav-link {
  font-size: 0.8125rem;
  color: #444a55;
  text-decoration: none;
  transition: color 90ms cubic-bezier(0.4, 0, 0.2, 1);
}
.ds-nav-link:hover,
.ds-nav-link.is-active {
  color: #161a22;
  font-weight: 500;
}
.ds-nav-cta {
  display: inline-flex;
  align-items: center;
  height: 36px;
  padding: 0 16px;
  font-family: 'Chillax-Variable', 'Chillax', system-ui, sans-serif;
  font-size: 0.8125rem;
  font-weight: 500;
  color: #f9fafb;
  background: #161a22;
  border: 1px solid #161a22;
  border-radius: 5px;
  box-shadow: inset 0 1px 0 hsl(0 0% 100% / 0.14);
  cursor: pointer;
}
.ds-nav-cta:hover {
  filter: brightness(1.18);
}
@media (max-width: 640px) {
  .ds-nav-links {
    display: none;
  }
}
